--
-- Name: dns_records_instance; Type: VIEW; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.dns_records_instance AS
 SELECT
        CASE
            WHEN (family((ip_addrs.value)::inet) = 6) THEN concat(replace(ip_addrs.value, ':'::text, '-'::text), '.', d.name, '.')
            ELSE concat(regexp_replace(ip_addrs.value, '\.'::text, '-'::text, 'g'::text), '.', d.name, '.')
        END AS q_name,
    (ip_addrs.value)::inet AS resource_record,
    (COALESCE(rt.type_name, (
        CASE
            WHEN (family((ip_addrs.value)::inet) = 6) THEN 'AAAA'::text
            ELSE 'A'::text
        END)::character varying))::character varying(10) AS q_type,
    meta.ttl,
    d.id AS domain_id
   FROM ((((((public.instances i
     JOIN public.machine_interfaces mi ON (((i.machine_id)::text = (mi.machine_id)::text)))
     JOIN public.domains d ON ((mi.domain_id = d.id)))
     CROSS JOIN LATERAL jsonb_array_elements((i.network_config -> 'interfaces'::text)) iface(value))
     CROSS JOIN LATERAL jsonb_each_text((iface.value -> 'ip_addrs'::text)) ip_addrs(key, value))
     LEFT JOIN public.dns_record_metadata meta ON ((meta.id = mi.id)))
     LEFT JOIN public.dns_record_types rt ON ((meta.record_type_id = rt.id)))
  WHERE (((iface.value -> 'function_id'::text) ->> 'type'::text) = 'physical'::text);


--
-- Name: dns_records_machines; Type: VIEW; Schema: public; Owner: -
--

CREATE OR REPLACE VIEW public.dns_records_machines AS
 SELECT q_name,
    resource_record
   FROM (((public.dns_records_shortname_combined
     FULL JOIN public.dns_records_adm_combined USING (q_name, resource_record))
     FULL JOIN public.dns_records_bmc_host_id USING (q_name, resource_record))
     FULL JOIN public.dns_records_bmc_dpu_id USING (q_name, resource_record));


